#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define MAX_N 5
#define MAX_M 100

int N, M;
double P[MAX_N][MAX_M];
double dp[MAX_N][MAX_M];

void calculate_expected_matching() {
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            dp[i][j] = 0;
        }
    }
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            if (i == 0 && j == 0) {
                dp[i][j] = P[i][j];
            } else if (i == 0) {
                dp[i][j] = dp[i][j-1] + P[i][j];
            } else if (j == 0) {
                dp[i][j] = dp[i-1][j] + P[i][j];
            } else {
                dp[i][j] = (dp[i-1][j-1] + P[i][j]) * P[i][j] + (dp[i-1][j] + (1-P[i][j])) * (1-P[i][j]);
            }
        }
    }
    printf("%.6f\n", dp[N-1][M-1]);
}

int main() {
    scanf("%d %d", &N, &M);
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            scanf("%lf", &P[i][j]);
        }
    }
    calculate_expected_matching();
    return 0;
}

